#include <stdio.h>

void array_operations(int size) {
 int array[size];
 for (int i = 0; i < size; i++) {
 array[i] = i * 2;
 }
 for (int i = 0; i < size; i++) {
 printf("%d ", array[i]);
 }
}

int main() {
 array_operations(5);
 return 0;
}
